parameters.jsCode:
const webhook = $('Webhook').item.json.body;

let logRows = [];
let decisionRows = [];
let profile = {};

try { logRows = $('Read Practice_Log').all().map(r => r.json); } catch(e) {}
try { decisionRows = $('Read Agent_Decisions').all().map(r => r.json); } catch(e) {}
try { profile = $('Read Child_Profile').first()?.json || {}; } catch(e) {}

const sessionCount = logRows.length;
const avgAccuracy = sessionCount
  ? Math.round(logRows.reduce((s, r) => s + Number(r.Practice_Rating_Score || 0), 0) / sessionCount)
  : 0;
const totalMins = logRows.reduce((s, r) => s + Number(r.Duration_Minutes || 0), 0);

return [{
  json: {
    child: webhook.child,
    week_start: webhook.week_start,
    include_therapist: webhook.include_therapist,
    profile,
    weekSessions: logRows,
    weekDecisions: decisionRows,
    stats: { sessionCount, avgAccuracy, totalMins }
  }
}];

// Parse Claude's JSON response
const raw = $json.content[0].text.trim();
let parsed;
try {
  parsed = JSON.parse(raw);
} catch(e) {
  const match = raw.match(/\{[\s\S]*\}/);
  parsed = match ? JSON.parse(match[0]) : {};
}

const webhook = $('Webhook').item.json.body;
const summaryId = `WS${Date.now()}`;

// Row to write to Weekly_Summaries (only after parent approval — done via /save endpoint)
const summaryRow = {
  Summary_ID:          summaryId,
  Child_Name:          webhook.child,
  Week_Start:          webhook.week_start,
  Summary_Text:        parsed.summary || '',
  Escalation_Flag:     parsed.escalation_flag ? 'Yes' : 'No',
  Escalation_Reason:   parsed.escalation_reason || '',
  Therapist_Draft:     parsed.therapist_draft || '',
  Therapist_Approved:  'Pending',
  Next_Week_Focus:     parsed.next_week_focus || '',
  Generated_Date:      new Date().toISOString().slice(0, 10),
};

return [{
  json: {
    parsed,
    summaryId,
    summaryRow,
  }
}];

